import React from 'react';
import { ComfortScore } from '@/components/ComfortScore';
import { MetricCard } from '@/components/MetricCard';
import { cities as CITIES } from '@/lib/cities';

export default async function CityPage({ params }: { params: { city: string } }) {
  const city = params.city.toLowerCase();
  const config = CITIES[city];

  if (!config) return <div>City not found</div>;

  // For initial server side render
  const res = await fetch(`http://localhost:3000/api/comfort?lat=${config.lat}&lon=${config.lon}`);
  const data = await res.json();

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold mb-6">{city} Dashboard</h1>
      <ComfortScore score={data.totalScore} />
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
        {Object.entries(data.subScores).map(([key, sub]: [string, any]) => (
          <MetricCard 
            key={key} 
            name={key} 
            normalizedScore={sub.normalized} 
            rawValue={sub.value.toString()} 
            icon="temp" 
          />
        ))}
      </div>
    </div>
  );
}import React from 'react';

interface ComfortScoreProps {
  score: number;
}

export const ComfortScore: React.FC<ComfortScoreProps> = ({ score }) => {
  const getColor = (s: number) => {
    if (s > 70) return 'text-green-500';
    if (s > 40) return 'text-yellow-500';
    return 'text-red-500';
  };

  return (
    <div className="flex flex-col items-center justify-center p-6 bg-card rounded-xl shadow">
      <div className={`text-6xl font-bold ${getColor(score)}`}>{Math.round(score)}</div>
      <div className="text-sm text-muted-foreground">Comfort Score</div>
    </div>
  );
};import { DataModule } from '../../types';
import { weatherModule } from './weather';
import { airModule } from './air';
import { uvModule } from './uv';
import { marineModule } from './marine';
import { earthquakeModule } from './earthquake';
import { fireModule } from './fire';
import { pollenModule } from './pollen';
import { pressureModule } from './pressure';
import { geomagneticModule } from './geomagnetic';
import { moonModule } from './moon';
import { daylightModule } from './daylight';

